// Custom logger middleware
function requestLogger(req, res, next) {
  const start = Date.now();
  console.log(`--> ${req.method} ${req.url}`);

  // Hook into the 'finish' event to log response time
  res.on('finish', () => {
    const ms = Date.now() - start;
