io.on('connection', (socket) => {
  // Join a named room
  socket.on('joinRoom', (room) => {
    socket.join(room);
    socket.to(room).emit('system', `A new user joined ${room}`);
  });

  // Send only to members of a room
  socket.on('roomMessage', ({ room, text }) => {
    io.to(room).emit('message', { text, from: socket.id });
  });

  // Leave a room
  socket.on('leaveRoom', (room) => {
    socket.leave(room);
    socket.to(room).emit('system', 'A user has left');
  });
});

