require('dotenv').config();
const express      = require('express');
const helmet       = require('helmet');
const rateLimit    = require('express-rate-limit');
const mongoSanitize = require('express-mongo-sanitize');
const xss          = require('xss-clean');

const app = express();

// Set security HTTP headers
app.use(helmet());

// Body parsing (limit payload size)
app.use(express.json({ limit: '10kb' }));

// Sanitise against NoSQL injection (strips $ operators from req.body)
app.use(mongoSanitize());

// Sanitise against XSS (strips HTML tags from user input)
app.use(xss());

// Rate limit: 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests, please try again later.'
});
app.use('/api', limiter);

app.get('/', (req, res) => res.send('Secured!'));
app.listen(3000);

const cors = require('cors');

// Restrict cross-origin requests to trusted origins only
const corsOptions = {
  origin: (origin, callback) => {
    const whitelist = ['https://myapp.com', 'https://admin.myapp.com'];
    if (!origin || whitelist.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error('Not allowed by CORS'));
    }
  },
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true
};

app.use(cors(corsOptions));

